sql:
SELECT match_id
FROM matches
WHERE attendance < (SELECT AVG(attendance) FROM matches);

SELECT AVG(m.attendance) AS average_attendance
FROM matches m
WHERE m.result = 'win';

external_knowledge:
- 'Captains' refers to the coach_name of the teams;
- 'Vessels' metaphorically refers to the team_name;
- 'Voyages' represents the matches_played;
- 'Storm waves' is a metaphor for goals scored by the players;
- 'Favorable winds' symbolizes assists made by the players.
